<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>FreshMart Grocery Store</title>
    <style>
        body {
            font-family: Arial, sans-serif;
            margin: 0;
            padding: 0;
            background-color: #fafafa;
        }
        header {
            background-color: #4caf50;
            color: white;
            padding: 1.5em 1em 1em 1em;
            text-align: center;
        }
        .section {
            margin: 2em auto;
            max-width: 800px;
            background: white;
            box-shadow: 0 0 10px rgba(0,0,0,0.07);
            padding: 2em; 
            border-radius: 8px;
        }
        h2 {
            color: #388e3c;
        }
        ul.products {
            list-style: none;
            padding: 0;
            display: flex;
            flex-wrap: wrap;
            gap: 2em;
        }
        ul.products li {
            background: #f0fbe2;
            border: 1px solid #c6e3b4;
            border-radius: 6px;
            flex: 1 0 180px;
            text-align: center;
            padding: 1em;
        }
        .footer {
            text-align: center;
            margin: 2em 0 0 0;
            color: #666;
        }
    </style>
</head>
<body>
    <header>
        <h1>FreshMart Grocery Store</h1>
        <p>Your neighborhood shop for fresh food and essentials</p>
    </header>
    <div class="section">
        <h2>Welcome!</h2>
        <p>Discover the freshest fruits, vegetables, and everyday essentials. Visit FreshMart for quality products and friendly service, right in your neighborhood.</p>
    </div>
    <div class="section">
        <h2>Featured Products</h2>
        <ul class="products">
            <li>
                <strong>Fresh Apples</strong><br>
                $1.99/lb<br>
                Crisp & Sweet!
            </li>
            <li>
                <strong>Organic Spinach</strong><br>
                $2.50/bag<br>
                Local Farms
            </li>
            <li>
                <strong>Whole Wheat Bread</strong><br>
                $2.20/loaf<br>
                Baked Daily
            </li>
            <li>
                <strong>Milk (1 Gallon)</strong><br>
                $3.09<br>
                Farm Fresh
            </li>
        </ul>
    </div>
    <div class="section">
        <h2>Store Information</h2>
        <p><strong>Address:</strong> 123 Main Street, Yourtown</p>
        <p><strong>Open:</strong> Mon–Sat 8:00am–8:00pm, Sun 10:00am–6:00pm</p>
        <p><strong>Phone:</strong> (555) 123-4567</p>
    </div>
    <div class="footer">
        &copy; 2026 FreshMart Grocery Store
    </div>
</body>
</html>
